import { useEffect, useRef } from 'react';

const pageCss = ":root{\n    --bg:           #F8F9FA;\n    --bg-alt:       #FAFAF8;\n    --heading:      #2D3748;\n    --body:         #4A5568;\n    --muted:        #718096;\n    --accent-soft:  #8FBC8F;\n    --line:         #B38B6D;\n    --line-soft:    rgba(179, 139, 109, .28);\n    --line-faint:   rgba(45, 55, 72, .08);\n    --cta:          #576DB5;\n    --cta-hover:    #46599C;\n    --link:         #1E3A8A;\n    --font: 'Plus Jakarta Sans', system-ui, -apple-system, Segoe UI, sans-serif;\n    --max: 1320px;\n    --gutter: 24px;\n    --pad: clamp(20px, 4vw, 48px);\n  }\n\n  *{ box-sizing:border-box; }\n  html,body{ margin:0; padding:0; }\n  body{\n    background: var(--bg);\n    color: var(--body);\n    font-family: var(--font);\n    font-size: 16px; line-height: 1.6;\n    -webkit-font-smoothing: antialiased;\n    text-rendering: optimizeLegibility;\n    overflow-x: hidden;\n  }\n  a{ color: inherit; text-decoration: none; }\n  button{ font-family: inherit; cursor: pointer; border: 0; background: transparent; }\n\n  /* ============ NAV (matches home) ============ */\n  .nav-wrap{\n    position:sticky; top:0; z-index:50;\n    backdrop-filter: blur(14px) saturate(140%);\n    -webkit-backdrop-filter: blur(14px) saturate(140%);\n    background: rgba(248, 249, 250, .72);\n    border-bottom: 1px solid var(--line-soft);\n  }\n  .container{\n    max-width: var(--max);\n    margin: 0 auto;\n    padding-left: var(--pad);\n    padding-right: var(--pad);\n    position: relative;\n  }\n  .nav{\n    display:grid; grid-template-columns: auto 1fr auto;\n    align-items:center; height:78px; gap:32px;\n  }\n  .logo{ display:flex; align-items:center; height:40px; }\n  .logo img{ height:38px; width:auto; display:block; }\n  .menu{ display:flex; justify-content:center; gap:6px; }\n  .menu a, .menu button.menu-link{\n    position:relative;\n    display:inline-flex; align-items:center; gap:6px;\n    padding:10px 14px;\n    font-size:14.5px; font-weight:500;\n    color:var(--body); border-radius:8px;\n    transition: color .2s ease, background .2s ease;\n  }\n  .menu a:hover, .menu button.menu-link:hover{ color:var(--heading); background: rgba(179,139,109,.06); }\n  .menu a::after{\n    content:\"\"; position:absolute; left:14px; right:14px; bottom:6px;\n    height:1px; background:var(--line); transform:scaleX(0); transform-origin:left;\n    transition: transform .25s ease;\n  }\n  .menu a:hover::after, .menu a.is-active::after{ transform:scaleX(1); }\n  .menu a.is-active{ color: var(--heading); }\n  .menu .chev{ width:12px; height:12px; color:var(--muted); }\n\n  .nav-right{ display:flex; align-items:center; gap:8px; }\n  .lang{\n    display:inline-flex; align-items:center; gap:6px;\n    padding: 9px 12px;\n    font-size:13.5px; font-weight:600;\n    color:var(--body);\n    border:1px solid var(--line-soft);\n    border-radius: 999px;\n    background: rgba(255,255,255,.5);\n    transition: border-color .2s, color .2s, background .2s;\n  }\n  .lang:hover{ border-color:var(--line); color:var(--heading); background:#fff; }\n  .lang .globe{ color:var(--line); }\n  .lang .chev{ color:var(--muted); }\n  .icon-btn{\n    width:40px; height:40px;\n    display:grid; place-items:center;\n    border-radius:50%;\n    border:1px solid var(--line-soft);\n    color:var(--body);\n    background: rgba(255,255,255,.5);\n    transition: border-color .2s, color .2s, background .2s;\n  }\n  .icon-btn:hover{ border-color:var(--line); color:var(--heading); background:#fff; }\n\n  /* ============ SERVICE HERO ============ */\n  .svc-hero{\n    position:relative;\n    background:\n      radial-gradient(900px 480px at 88% 12%, rgba(143,188,143,.12), transparent 65%),\n      radial-gradient(720px 480px at 12% 92%, rgba(179,139,109,.08), transparent 70%),\n      var(--bg);\n    padding: clamp(72px, 9vw, 128px) 0 clamp(72px, 9vw, 128px);\n    overflow:hidden;\n    border-bottom: 1px solid var(--line-faint);\n  }\n  .svc-hero::before{\n    content:\"\";\n    position:absolute; inset:0;\n    background-image: linear-gradient(to right, rgba(45,55,72,.022) 1px, transparent 1px);\n    background-size: calc((100% - 2 * var(--pad)) / 12) 100%;\n    background-position: var(--pad) 0;\n    background-repeat: no-repeat;\n    max-width: var(--max);\n    margin: 0 auto;\n    left: 0; right: 0;\n    pointer-events: none;\n  }\n\n  .svc-grid{\n    display:grid;\n    grid-template-columns: minmax(0, 1fr) minmax(440px, 540px);\n    gap: clamp(32px, 4vw, 56px);\n    align-items: center;\n    position:relative;\n  }\n\n  /* CENTER stage */\n  .svc-stage{\n    grid-column: 1 / 2;\n    position:relative;\n    z-index: 1;\n  }\n  .svc-h1{\n    font-size: clamp(48px, 8vw, 124px);\n    line-height: .96;\n    letter-spacing: -0.04em;\n    color: var(--heading);\n    font-weight: 700;\n    margin: 0;\n    text-wrap: balance;\n  }\n  .svc-h1 .word-italic{\n    font-style: italic;\n    font-weight: 600;\n    color: var(--heading);\n  }\n  .svc-h1 .word-accent{\n    position: relative;\n    display: inline-block;\n    color: var(--heading);\n  }\n  .svc-h1 .word-accent::before{\n    content:\"\";\n    position:absolute;\n    left: -2px; right: -2px;\n    bottom: 0.06em;\n    height: 14px;\n    background: linear-gradient(90deg, rgba(179,139,109,.32), rgba(143,188,143,.30));\n    border-radius: 3px;\n    z-index: -1;\n    transform: skewX(-6deg);\n  }\n\n  /* TOP-RIGHT corner CTA */\n  .svc-cta-corner{\n    grid-column: 2 / 3;\n    justify-self: end;\n    align-self: start;\n    margin-top: 4px;\n  }\n  .svc-cta-corner a{\n    display:inline-flex; align-items:center; gap: 12px;\n    padding: 6px 6px 6px 18px;\n    background: rgba(255,255,255,.65);\n    backdrop-filter: blur(14px) saturate(140%);\n    -webkit-backdrop-filter: blur(14px) saturate(140%);\n    border: 1px solid var(--line-soft);\n    border-radius: 999px;\n    font-size: 13.5px;\n    font-weight: 600;\n    color: var(--heading);\n    letter-spacing: -0.005em;\n    transition: border-color .25s, background .25s, transform .25s, color .25s;\n    box-shadow: 0 8px 24px -16px rgba(45,55,72,.18);\n    white-space: nowrap;\n    text-decoration: none;\n  }\n  .svc-cta-corner a:hover{\n    border-color: var(--line);\n    background: #fff;\n    transform: translateY(-2px);\n  }\n  .svc-cta-corner .ico{\n    width: 36px; height: 36px;\n    border-radius: 50%;\n    background: var(--cta);\n    color: #fff;\n    display:grid; place-items:center;\n    flex: 0 0 36px;\n    transition: background .2s, transform .25s;\n  }\n  .svc-cta-corner a:hover .ico{ background: var(--cta-hover); transform: rotate(-12deg); }\n\n  /* Floating glass tags around heading — orbital pattern */\n  .svc-orbit{\n    grid-column: 2 / 3;\n    position: relative;\n    width: 100%;\n    aspect-ratio: 1;\n    max-width: 540px;\n    margin: 0 auto;\n    pointer-events: none;\n    z-index: 0;\n    align-self: center;\n  }\n\n  /* Center glass hub with TheNextGen logo */\n  .svc-orbit-hub{\n    position:absolute;\n    top: 50%; left: 50%;\n    transform: translate(-50%, -50%);\n    width: 156px; height: 156px;\n    border-radius: 50%;\n    background: rgba(255,255,255,.82);\n    backdrop-filter: blur(16px) saturate(140%);\n    -webkit-backdrop-filter: blur(16px) saturate(140%);\n    border: 1px solid var(--line-soft);\n    box-shadow:\n      0 28px 56px -16px rgba(45,55,72,.20),\n      inset 0 1px 0 rgba(255,255,255,.6);\n    display:grid; place-items:center;\n    z-index: 1;\n    animation: hubPulse 4s ease-in-out infinite;\n  }\n  .svc-orbit-hub::before{\n    content:\"\";\n    position: absolute; inset: -14px;\n    border-radius: 50%;\n    border: 1px dashed rgba(179,139,109,.30);\n    animation: spin 28s linear infinite;\n  }\n  .svc-orbit-hub::after{\n    content:\"\";\n    position: absolute; inset: -36px;\n    border-radius: 50%;\n    border: 1px dashed rgba(143,188,143,.22);\n    animation: spin 42s linear infinite reverse;\n  }\n  .svc-orbit-hub-inner{\n    text-align: center;\n    line-height: 1;\n  }\n  .svc-orbit-hub-mark{\n    font-size: 30px;\n    font-weight: 800;\n    letter-spacing: -0.04em;\n    color: var(--cta);\n    line-height: 1;\n    margin-bottom: 6px;\n  }\n  .svc-orbit-hub-name{\n    font-size: 10px;\n    font-weight: 700;\n    letter-spacing: .18em;\n    text-transform: uppercase;\n    color: var(--heading);\n    line-height: 1.2;\n    display:block;\n  }\n  .svc-orbit-hub-tag{\n    font-size: 9px;\n    font-weight: 600;\n    letter-spacing: .16em;\n    text-transform: uppercase;\n    color: var(--muted);\n    line-height: 1;\n    display:block;\n    margin-top: 4px;\n  }\n\n  /* Orbiting service pills */\n  .svc-float{\n    position:absolute;\n    display:inline-flex; align-items:center; gap: 8px;\n    padding: 9px 16px 9px 11px;\n    background: rgba(255,255,255,.85);\n    backdrop-filter: blur(14px) saturate(140%);\n    -webkit-backdrop-filter: blur(14px) saturate(140%);\n    border: 1px solid rgba(179,139,109,.32);\n    border-radius: 999px;\n    font-size: 12.5px;\n    font-weight: 600;\n    color: var(--heading);\n    box-shadow: 0 16px 32px -18px rgba(45,55,72,.22);\n    pointer-events: none;\n    white-space: nowrap;\n    animation: drift 8s ease-in-out infinite;\n    z-index: 2;\n  }\n  .svc-float .tag-ico{\n    width: 20px; height: 20px;\n    border-radius: 50%;\n    display:grid; place-items:center;\n    flex: 0 0 20px;\n  }\n  /* 6 evenly distributed positions on a circle around 540px container */\n  .svc-float.f1{ top: 6%;    left: 50%;  transform: translateX(-50%); animation-delay: 0s; }\n  .svc-float.f1 .tag-ico{ background: rgba(143,188,143,.22); color: var(--accent-soft); }\n\n  .svc-float.f2{ top: 24%;   right: 4%;  animation-delay: -1.3s; }\n  .svc-float.f2 .tag-ico{ background: rgba(87,109,181,.16); color: var(--cta); }\n\n  .svc-float.f3{ bottom: 24%; right: 4%; animation-delay: -2.6s; }\n  .svc-float.f3 .tag-ico{ background: rgba(179,139,109,.22); color: var(--line); }\n\n  .svc-float.f4{ bottom: 6%; left: 50%;  transform: translateX(-50%); animation-delay: -4s; }\n  .svc-float.f4 .tag-ico{ background: rgba(143,188,143,.22); color: var(--accent-soft); }\n\n  .svc-float.f5{ bottom: 24%; left: 4%;  animation-delay: -5.3s; }\n  .svc-float.f5 .tag-ico{ background: rgba(87,109,181,.16); color: var(--cta); }\n\n  .svc-float.f6{ top: 24%;   left: 4%;   animation-delay: -6.6s; }\n  .svc-float.f6 .tag-ico{ background: rgba(179,139,109,.22); color: var(--line); }\n\n  /* override drift translate for centered pills (f1, f4) so it preserves translateX */\n  .svc-float.f1, .svc-float.f4{ animation-name: driftCenter; }\n\n  @keyframes drift{\n    0%,100%{ transform: translateY(0); }\n    50%   { transform: translateY(-9px); }\n  }\n  @keyframes driftCenter{\n    0%,100%{ transform: translateX(-50%) translateY(0); }\n    50%   { transform: translateX(-50%) translateY(-9px); }\n  }\n  @keyframes spin{\n    to{ transform: rotate(360deg); }\n  }\n  @keyframes hubPulse{\n    0%,100%{ box-shadow: 0 28px 56px -16px rgba(45,55,72,.20), inset 0 1px 0 rgba(255,255,255,.6), 0 0 0 0 rgba(143,188,143,0); }\n    50%   { box-shadow: 0 28px 56px -16px rgba(45,55,72,.20), inset 0 1px 0 rgba(255,255,255,.6), 0 0 0 14px rgba(143,188,143,.06); }\n  }\n  @media (prefers-reduced-motion: reduce){\n    .svc-orbit-hub::before, .svc-orbit-hub::after{ animation: none; }\n    .svc-orbit-hub{ animation: none; }\n    .svc-float{ animation: none; }\n  }\n\n  /* Bottom row — meta strip + sub paragraph + CTAs */\n  .svc-sub-row{\n    grid-column: 1 / -1;\n    margin-top: clamp(48px, 6vw, 80px);\n    display:grid;\n    grid-template-columns: repeat(12, 1fr);\n    gap: var(--gutter);\n    align-items: end;\n  }\n  .svc-meta{\n    grid-column: 1 / span 7;\n    display:flex; align-items:center; gap: 14px;\n    padding-bottom: 6px;\n  }\n  .svc-meta .bar{\n    flex: 1;\n    height: 1px;\n    background: var(--line-faint);\n    max-width: 280px;\n  }\n  .svc-meta-label{\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n    color: var(--muted);\n  }\n  .svc-sub{\n    grid-column: 8 / -1;\n    font-size: clamp(15px, 1.2vw, 17px);\n    line-height: 1.65;\n    color: var(--body);\n    margin: 0;\n    max-width: 56ch;\n    font-weight: 500;\n  }\n\n  /* CTAs right below the H1 */\n  .svc-stage-cta{\n    margin-top: clamp(28px, 3.4vw, 40px);\n    display: flex;\n    align-items: center;\n    gap: 24px;\n    flex-wrap: wrap;\n  }\n\n  .svc-cta-primary{\n    display:inline-flex; align-items:center; gap: 12px;\n    padding: 16px 8px 16px 24px;\n    background: var(--cta);\n    color: #fff;\n    font-family: inherit;\n    font-size: 15px;\n    font-weight: 600;\n    letter-spacing: -0.005em;\n    border-radius: 999px;\n    text-decoration: none;\n    border: 0;\n    cursor: pointer;\n    box-shadow:\n      0 1px 0 rgba(255,255,255,.20) inset,\n      0 12px 32px -10px rgba(87,109,181,.50);\n    transition: transform .2s, background .2s, box-shadow .25s;\n  }\n  .svc-cta-primary:hover{\n    background: var(--cta-hover);\n    transform: translateY(-2px);\n    box-shadow:\n      0 1px 0 rgba(255,255,255,.20) inset,\n      0 18px 42px -10px rgba(87,109,181,.65);\n  }\n  .svc-cta-primary .ico{\n    width: 32px; height: 32px;\n    border-radius: 50%;\n    background: rgba(255,255,255,.18);\n    display:grid; place-items:center;\n    flex: 0 0 32px;\n    transition: background .25s, transform .3s;\n  }\n  .svc-cta-primary:hover .ico{ background: rgba(255,255,255,.30); transform: rotate(-12deg); }\n\n  /* ======== CAPABILITY MARQUEE ======== */\n  .svc-bottom{\n    grid-column: 1 / -1;\n    margin-top: clamp(56px, 7vw, 88px);\n    padding-top: 32px;\n    border-top: 1px solid var(--line-faint);\n    display: grid;\n    grid-template-columns: auto 1fr;\n    align-items: center;\n    gap: clamp(20px, 2.4vw, 36px);\n  }\n  .svc-bottom-label{\n    font-size: 13px;\n    font-weight: 700;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n    color: var(--heading);\n    white-space: nowrap;\n    display: inline-flex; align-items: center; gap: 10px;\n  }\n  .svc-bottom-label::before{\n    content:\"\"; width:8px; height:8px; border-radius:50%;\n    background: var(--accent-soft);\n    box-shadow: 0 0 0 4px rgba(143,188,143,.18);\n  }\n\n  .svc-marquee{\n    position: relative;\n    overflow: hidden;\n    background: rgba(255,255,255,.72);\n    backdrop-filter: blur(12px) saturate(140%);\n    -webkit-backdrop-filter: blur(12px) saturate(140%);\n    border: 1px solid var(--line-soft);\n    border-radius: 999px;\n    padding: 18px 0;\n    box-shadow: 0 12px 32px -20px rgba(45, 55, 72, .15);\n    -webkit-mask-image: linear-gradient(90deg, transparent 0, #000 6%, #000 94%, transparent 100%);\n            mask-image: linear-gradient(90deg, transparent 0, #000 6%, #000 94%, transparent 100%);\n  }\n  .svc-marquee-track{\n    display: flex;\n    align-items: center;\n    gap: clamp(36px, 4.5vw, 64px);\n    width: max-content;\n    animation: marqueeScroll 50s linear infinite;\n  }\n  .svc-marquee:hover .svc-marquee-track{ animation-play-state: paused; }\n\n  .svc-marquee-item{\n    display: inline-flex; align-items: center; gap: 12px;\n    font-size: clamp(15px, 1.2vw, 17px);\n    font-weight: 700;\n    color: var(--heading);\n    letter-spacing: -0.012em;\n    white-space: nowrap;\n    padding: 6px 0;\n  }\n  .svc-marquee-item::before{\n    content:\"\"; width: 8px; height: 8px; border-radius: 50%;\n    background: var(--accent-soft);\n    flex: 0 0 8px;\n  }\n  .svc-marquee-item:nth-child(3n)::before{ background: var(--line); }\n  .svc-marquee-item:nth-child(3n+2)::before{ background: var(--cta); }\n\n  @keyframes marqueeScroll{\n    0%   { transform: translateX(0); }\n    100% { transform: translateX(-50%); }\n  }\n  @media (prefers-reduced-motion: reduce){\n    .svc-marquee-track{ animation: none; }\n  }\n\n  .svc-cta-link{\n    display:inline-flex; align-items:center; gap: 10px;\n    color: var(--heading);\n    font-size: 14px;\n    font-weight: 600;\n    letter-spacing: -0.005em;\n    text-decoration: none;\n    transition: gap .25s ease, color .2s;\n  }\n  .svc-cta-link:hover{ color: var(--cta); gap: 14px; }\n  .svc-cta-link .ico{\n    width: 32px; height: 32px;\n    border-radius: 50%;\n    border: 1px solid var(--line-soft);\n    color: var(--line);\n    display: grid; place-items: center;\n    transition: border-color .25s, background .25s, color .25s, transform .3s;\n  }\n  .svc-cta-link:hover .ico{\n    border-color: var(--line);\n    background: var(--line);\n    color: #fff;\n    transform: rotate(-12deg);\n  }\n\n  /* Reveal */\n  .reveal{ opacity:0; transform: translateY(14px); animation: rise .9s cubic-bezier(.2,.7,.2,1) forwards; }\n  .reveal.d1{ animation-delay:.05s; }\n  .reveal.d2{ animation-delay:.15s; }\n  .reveal.d3{ animation-delay:.25s; }\n  .reveal.d4{ animation-delay:.35s; }\n  .reveal.d5{ animation-delay:.45s; }\n  @keyframes rise{ to { opacity:1; transform:none; } }\n\n  /* Responsive */\n  @media (max-width: 1100px){\n    .svc-grid{ grid-template-columns: minmax(0, 1fr) minmax(360px, 460px); gap: 32px; }\n    .svc-orbit{ max-width: 460px; }\n  }\n  @media (max-width: 1024px){\n    .menu{ display:none; }\n    .svc-grid{ grid-template-columns: 1fr; gap: 16px; }\n    .svc-stage{ grid-column: 1 / -1; }\n    .svc-meta{ grid-column: 1 / -1; }\n    .svc-sub{ grid-column: 1 / -1; padding-top: 16px; }\n    .svc-orbit{ display: none; }\n  }\n  @media (max-width: 640px){\n    .nav{ height:64px; gap:12px; }\n    .logo img{ height:30px; }\n    .lang{ display:none; }\n    .svc-cta-corner a{ width: 100%; justify-content: space-between; }\n    .svc-float{ font-size: 11px; padding: 7px 11px 7px 8px; }\n    .svc-stage-cta .svc-cta-primary{ width: 100%; justify-content: space-between; }\n    .svc-bottom{ grid-template-columns: 1fr; gap: 14px; }\n    .svc-bottom-label{ width: 100%; margin-bottom: 4px; }\n  }\n\n    /* ============ SERVICES LIST ============ */\n  .svc-list{\n    position:relative;\n    background: var(--bg);  /* #F8F9FA */\n    padding: clamp(72px, 9vw, 128px) 0 clamp(80px, 10vw, 140px);\n    border-top: 1px solid var(--line-faint);\n  }\n\n  .svc-list-head{\n    display:grid;\n    grid-template-columns: repeat(12, 1fr);\n    gap: var(--gutter);\n    align-items: end;\n    margin-bottom: clamp(48px, 6vw, 80px);\n  }\n  .svc-list-eyebrow{\n    grid-column: 1 / span 12;\n    display:inline-flex; align-items:center; gap:10px;\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .24em;\n    text-transform: uppercase;\n    color: var(--muted);\n    margin-bottom: 20px;\n  }\n  .svc-list-eyebrow::before{\n    content:\"\"; width:7px; height:7px; border-radius:50%;\n    background: var(--accent-soft);\n  }\n  .svc-list-h2{\n    grid-column: 1 / span 7;\n    font-size: clamp(34px, 4.2vw, 56px);\n    line-height: 1.04;\n    letter-spacing: -0.025em;\n    color: var(--heading);\n    font-weight: 700;\n    margin: 0;\n    max-width: 14ch;\n  }\n  .svc-list-sub{\n    grid-column: 9 / span 4;\n    font-size: 15.5px;\n    line-height: 1.65;\n    color: var(--body);\n    margin: 0;\n    padding-bottom: 8px;\n  }\n  .svc-list-all{\n    grid-column: 1 / -1;\n    margin-top: 8px;\n    display:flex; align-items:center; gap: 14px;\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n    color: var(--muted);\n  }\n  .svc-list-all .bar{\n    flex: 1;\n    height: 1px;\n    background: var(--line-faint);\n    max-width: 320px;\n  }\n\n  /* Card grid — 3 cols × 4 rows */\n  .svc-cards{\n    display:grid;\n    grid-template-columns: repeat(3, 1fr);\n    gap: 0;\n    border-top: 1px solid var(--line-faint);\n    border-bottom: 1px solid var(--line-faint);\n  }\n\n  .svc-card{\n    position:relative;\n    display:flex; flex-direction:column;\n    padding: clamp(28px, 3vw, 36px);\n    background: transparent;\n    border-right: 1px solid var(--line-faint);\n    border-bottom: 1px solid var(--line-faint);\n    transition: background .35s ease;\n    text-decoration: none;\n    color: inherit;\n    overflow:hidden;\n  }\n  .svc-card:nth-child(3n){ border-right: none; }\n  .svc-card:nth-last-child(-n+3){ border-bottom: none; }\n\n  /* Hover top accent line */\n  .svc-card::before{\n    content:\"\";\n    position:absolute;\n    top: 0; left: 0; right: 0;\n    height: 2px;\n    background: var(--line);\n    transform: scaleX(0);\n    transform-origin: left;\n    transition: transform .45s cubic-bezier(.2,.7,.2,1);\n  }\n  .svc-card:hover{\n    background: rgba(255,255,255,.65);\n    backdrop-filter: blur(10px);\n    -webkit-backdrop-filter: blur(10px);\n  }\n  .svc-card:hover::before{ transform: scaleX(1); }\n  .svc-card:hover .svc-card-img{\n    border-color: var(--line);\n    background:\n      radial-gradient(circle at 50% 45%, rgba(143,188,143,.18), transparent 65%),\n      linear-gradient(180deg, #FFFFFF 0%, #F5F0E8 100%);\n    box-shadow: inset 0 1px 0 rgba(255,255,255,.8);\n  }\n  .svc-card:hover .svc-card-img::before{\n    transform: scale(1.1);\n    background: radial-gradient(closest-side, rgba(179,139,109,.22), transparent 70%);\n  }\n  .svc-card:hover .svc-card-img svg{\n    transform: translateY(-3px) scale(1.04);\n  }\n  .svc-card:hover .svc-card-arrow{\n    border-color: var(--line);\n    background: var(--line);\n    color: #fff;\n    transform: rotate(-12deg);\n  }\n  .svc-card:hover .svc-card-title{ color: var(--cta); }\n  .svc-card:hover .svc-card-sub{ color: var(--heading); }\n\n  /* Image area */\n  .svc-card-img{\n    position:relative;\n    aspect-ratio: 4 / 3;\n    border-radius: 14px;\n    overflow:hidden;\n    background:\n      radial-gradient(circle at 50% 45%, rgba(143,188,143,.10), transparent 65%),\n      linear-gradient(180deg, #FFFFFF 0%, #FAFAF8 100%);\n    border: 1px solid var(--line-faint);\n    margin-bottom: 24px;\n    transition: border-color .35s ease, transform .35s ease, box-shadow .35s ease, background .35s ease;\n  }\n  .svc-card-img::before{\n    content:\"\";\n    position:absolute;\n    inset: 12% 16% 18% 16%;\n    border-radius: 50%;\n    background: radial-gradient(closest-side, rgba(179,139,109,.12), transparent 70%);\n    z-index: 0;\n    transition: transform .6s cubic-bezier(.2,.7,.2,1), background .35s ease;\n  }\n  .svc-card-img::after{\n    content:\"\";\n    position:absolute;\n    top: 12px; right: 12px;\n    width: 28px; height: 28px;\n    border-radius: 50%;\n    background-image:\n      radial-gradient(circle at center, rgba(179,139,109,.45) 1px, transparent 1.6px);\n    background-size: 6px 6px;\n    background-position: 0 0;\n    opacity: .35;\n    z-index: 0;\n  }\n  .svc-card-img svg{\n    width:100%; height:100%; display:block;\n    position: relative;\n    z-index: 1;\n    transition: transform .5s cubic-bezier(.2,.7,.2,1);\n  }\n\n  .svc-card-arrow{\n    position:absolute;\n    bottom: 14px; left: 14px;\n    width: 38px; height: 38px;\n    border-radius: 50%;\n    background: rgba(255,255,255,.92);\n    backdrop-filter: blur(8px);\n    border: 1px solid var(--line-soft);\n    color: var(--line);\n    display:grid; place-items:center;\n    transition: background .3s, color .3s, transform .3s, border-color .3s;\n    z-index: 2;\n  }\n\n  .svc-card-meta{\n    display:flex; align-items:center; gap: 10px;\n    font-size: 11px;\n    font-weight: 600;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n    color: var(--muted);\n    margin-bottom: 10px;\n  }\n  .svc-card-meta::before{\n    content:\"\"; width:5px; height:5px; border-radius:50%;\n    background: var(--line);\n    flex: 0 0 5px;\n  }\n  .svc-card-title{\n    font-size: clamp(19px, 1.7vw, 22px);\n    font-weight: 700;\n    line-height: 1.25;\n    letter-spacing: -0.018em;\n    color: var(--heading);\n    margin: 0 0 8px;\n    transition: color .3s;\n  }\n  .svc-card-sub{\n    font-size: 13.5px;\n    line-height: 1.55;\n    color: var(--body);\n    margin: 0;\n    max-width: 32ch;\n    font-weight: 500;\n  }\n\n  @media (max-width: 1100px){\n    .svc-cards{ grid-template-columns: repeat(2, 1fr); }\n    .svc-card{ border-right: 1px solid var(--line-faint); border-bottom: 1px solid var(--line-faint); }\n    .svc-card:nth-child(3n){ border-right: 1px solid var(--line-faint); }\n    .svc-card:nth-child(2n){ border-right: none; }\n    .svc-card:nth-last-child(-n+3){ border-bottom: 1px solid var(--line-faint); }\n    .svc-card:nth-last-child(-n+2){ border-bottom: none; }\n\n    .svc-list-h2{ grid-column: 1 / -1; }\n    .svc-list-sub{ grid-column: 1 / -1; padding-top: 14px; padding-bottom: 0; }\n  }\n  @media (max-width: 640px){\n    .svc-cards{ grid-template-columns: 1fr; }\n    .svc-card{ border-right: none !important; }\n    .svc-card:nth-last-child(1){ border-bottom: none; }\n  }\n\n  /* See more toggle */\n  .svc-card.is-extra{\n    display: none;\n  }\n  .svc-list[data-expanded=\"true\"] .svc-card.is-extra{\n    display: flex;\n  }\n  .svc-more-row{\n    display:flex; justify-content:center;\n    margin-top: clamp(32px, 4vw, 48px);\n  }\n  .svc-more-btn{\n    display:inline-flex; align-items:center; gap: 12px;\n    padding: 14px 8px 14px 22px;\n    background: rgba(255,255,255,.65);\n    backdrop-filter: blur(12px) saturate(140%);\n    -webkit-backdrop-filter: blur(12px) saturate(140%);\n    border: 1px solid var(--line-soft);\n    border-radius: 999px;\n    font-size: 14px;\n    font-weight: 600;\n    color: var(--heading);\n    letter-spacing: -0.005em;\n    transition: border-color .25s, background .25s, transform .25s;\n    box-shadow: 0 8px 24px -16px rgba(45,55,72,.18);\n    cursor: pointer;\n  }\n  .svc-more-btn:hover{\n    border-color: var(--line);\n    background: #fff;\n    transform: translateY(-2px);\n  }\n  .svc-more-btn .ico{\n    width: 36px; height: 36px;\n    border-radius: 50%;\n    background: var(--cta);\n    color: #fff;\n    display:grid; place-items:center;\n    flex: 0 0 36px;\n    transition: background .25s, transform .35s;\n  }\n  .svc-more-btn:hover .ico{ background: var(--cta-hover); }\n  .svc-list[data-expanded=\"true\"] .svc-more-btn .ico{ transform: rotate(180deg); background: var(--line); }\n  .svc-more-btn .label-show{ display: inline; }\n  .svc-more-btn .label-hide{ display: none; }\n  .svc-list[data-expanded=\"true\"] .svc-more-btn .label-show{ display: none; }\n  .svc-list[data-expanded=\"true\"] .svc-more-btn .label-hide{ display: inline; }\n\n  /* ============ PILLARS SECTION (Custom Software + Automation) ============ */\n  .pillars{\n    position:relative;\n    background: var(--bg-alt); /* #FAFAF8 */\n    padding: clamp(72px, 9vw, 128px) 0;\n    border-top: 1px solid var(--line-faint);\n    overflow:hidden;\n  }\n  .pillars::before{\n    content:\"\";\n    position:absolute; inset:0;\n    background:\n      radial-gradient(700px 380px at 92% 8%, rgba(143,188,143,.08), transparent 70%),\n      radial-gradient(620px 320px at 6% 96%, rgba(179,139,109,.06), transparent 70%);\n    pointer-events:none;\n  }\n\n  .pillars-head{\n    display:grid;\n    grid-template-columns: repeat(12, 1fr);\n    gap: var(--gutter);\n    align-items: end;\n    margin-bottom: clamp(48px, 6vw, 72px);\n    position:relative;\n  }\n  .pillars-eyebrow{\n    grid-column: 1 / span 12;\n    display:inline-flex; align-items:center; gap:10px;\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .24em;\n    text-transform: uppercase;\n    color: var(--muted);\n    margin-bottom: 18px;\n  }\n  .pillars-eyebrow::before{\n    content:\"\"; width:7px; height:7px; border-radius:50%;\n    background: var(--accent-soft);\n  }\n  .pillars-h2{\n    grid-column: 1 / span 7;\n    font-size: clamp(34px, 4.2vw, 56px);\n    line-height: 1.04;\n    letter-spacing: -0.025em;\n    color: var(--heading);\n    font-weight: 700;\n    margin: 0;\n    max-width: 16ch;\n  }\n  .pillars-sub{\n    grid-column: 9 / span 4;\n    font-size: 15.5px;\n    line-height: 1.65;\n    color: var(--body);\n    margin: 0;\n    padding-bottom: 8px;\n  }\n\n  /* Layout */\n  .pillars-grid{\n    display:grid;\n    grid-template-columns: 1fr 1.55fr;\n    gap: clamp(32px, 4vw, 56px);\n    align-items: start;\n    position:relative;\n  }\n\n  /* LEFT — pillar list */\n  .pillar-list{\n    list-style:none;\n    margin:0; padding:0;\n    display:flex; flex-direction:column;\n  }\n  .pillar-item{\n    position:relative;\n    padding: 22px 0 22px 22px;\n    border-bottom: 1px solid var(--line-faint);\n    cursor: pointer;\n    transition: padding .25s ease;\n  }\n  .pillar-item:first-child{ border-top: 1px solid var(--line-faint); }\n  .pillar-item::before{\n    content:\"\";\n    position:absolute;\n    top: 22px; bottom: 22px;\n    left: 0;\n    width: 2px;\n    background: var(--line);\n    transform: scaleY(0);\n    transform-origin: top;\n    transition: transform .35s ease;\n  }\n  .pillar-item.is-active::before,\n  .pillar-item:hover::before{ transform: scaleY(1); }\n  .pillar-item.is-active .pillar-title{ color: var(--heading); }\n  .pillar-item:hover .pillar-title{ color: var(--heading); }\n\n  .pillar-title{\n    font-size: clamp(17px, 1.5vw, 20px);\n    font-weight: 700;\n    line-height: 1.2;\n    letter-spacing: -0.014em;\n    color: var(--body);\n    margin: 0 0 6px;\n    transition: color .25s ease;\n  }\n  .pillar-item.is-active .pillar-title{ color: var(--heading); }\n  .pillar-sub{\n    font-size: 13.5px;\n    line-height: 1.55;\n    color: var(--muted);\n    margin: 0;\n    font-weight: 500;\n    transition: color .25s ease;\n  }\n  .pillar-item.is-active .pillar-sub{ color: var(--body); }\n\n  /* RIGHT — detail card */\n  .pillar-detail{\n    position: relative;\n    background: rgba(255,255,255,.72);\n    backdrop-filter: blur(14px) saturate(140%);\n    -webkit-backdrop-filter: blur(14px) saturate(140%);\n    border: 1px solid var(--line-soft);\n    border-radius: 24px;\n    padding: clamp(32px, 4vw, 48px);\n    box-shadow: 0 24px 48px -32px rgba(45,55,72,.18);\n    min-height: 360px;\n  }\n\n  .pillar-detail-pane{\n    display: none;\n    flex-direction: column;\n    gap: 18px;\n    animation: fadeIn .35s cubic-bezier(.2,.7,.2,1);\n  }\n  .pillar-detail-pane.is-active{ display: flex; }\n  @keyframes fadeIn{\n    from{ opacity:0; transform: translateY(8px); }\n    to  { opacity:1; transform: none; }\n  }\n\n  .pdt-head{\n    display:flex; align-items:center; gap: 12px;\n    color: var(--muted);\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n  }\n  .pdt-head .num{\n    width: 28px; height: 28px;\n    border-radius: 50%;\n    border: 1px dashed var(--line);\n    color: var(--line);\n    display:grid; place-items:center;\n    font-size: 11px;\n    letter-spacing: 0;\n  }\n  .pdt-title{\n    font-size: clamp(24px, 2.4vw, 32px);\n    font-weight: 700;\n    line-height: 1.15;\n    letter-spacing: -0.022em;\n    color: var(--heading);\n    margin: 0;\n  }\n  .pdt-text{\n    font-size: 15px;\n    line-height: 1.65;\n    color: var(--body);\n    margin: 0;\n    max-width: 60ch;\n  }\n  .pdt-list{\n    list-style:none;\n    margin: 14px 0 0;\n    padding: 0;\n    display:grid;\n    gap: 10px;\n  }\n  .pdt-list li{\n    display:flex; align-items:flex-start; gap: 10px;\n    font-size: 14px;\n    color: var(--body);\n    line-height: 1.5;\n    font-weight: 500;\n  }\n  .pdt-list li::before{\n    content:\"\";\n    width: 6px; height: 6px;\n    border-radius: 50%;\n    background: var(--cta);\n    margin-top: 8px;\n    flex: 0 0 6px;\n  }\n  .pdt-list li strong{\n    color: var(--heading);\n    font-weight: 600;\n  }\n\n  .pdt-foot{\n    margin-top: 20px;\n    padding-top: 18px;\n    border-top: 1px solid var(--line-faint);\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .18em;\n    text-transform: uppercase;\n    color: var(--muted);\n  }\n\n  @media (max-width: 1024px){\n    .pillars-grid{ grid-template-columns: 1fr; gap: 32px; }\n    .pillars-h2{ grid-column: 1 / -1; }\n    .pillars-sub{ grid-column: 1 / -1; padding-top: 14px; padding-bottom: 0; }\n  }\n\n  /* ============ FEATURE PAIR (rounded photo cards) ============ */\n  .pair{\n    position:relative;\n    background: var(--bg);  /* #F8F9FA */\n    padding: clamp(72px, 9vw, 128px) 0;\n    border-top: 1px solid var(--line-faint);\n  }\n\n  .pair-head{\n    display:grid;\n    grid-template-columns: repeat(12, 1fr);\n    gap: var(--gutter);\n    align-items: end;\n    margin-bottom: clamp(48px, 6vw, 72px);\n  }\n  .pair-eyebrow{\n    grid-column: 1 / span 12;\n    display:inline-flex; align-items:center; gap:10px;\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .24em;\n    text-transform: uppercase;\n    color: var(--muted);\n    margin-bottom: 18px;\n  }\n  .pair-eyebrow::before{\n    content:\"\"; width:7px; height:7px; border-radius:50%;\n    background: var(--accent-soft);\n  }\n  .pair-h2{\n    grid-column: 1 / span 7;\n    font-size: clamp(34px, 4.2vw, 56px);\n    line-height: 1.04;\n    letter-spacing: -0.025em;\n    color: var(--heading);\n    font-weight: 700;\n    margin: 0;\n    max-width: 16ch;\n  }\n  .pair-sub{\n    grid-column: 9 / span 4;\n    font-size: 15.5px;\n    line-height: 1.65;\n    color: var(--body);\n    margin: 0;\n    padding-bottom: 8px;\n  }\n\n  /* Grid */\n  .pair-grid{\n    display:grid;\n    grid-template-columns: repeat(2, 1fr);\n    gap: clamp(20px, 2.5vw, 32px);\n  }\n\n  .pair-card{\n    position:relative;\n    aspect-ratio: 16 / 11;\n    border-radius: 28px;\n    overflow: hidden;\n    isolation: isolate;\n    text-decoration: none;\n    color: inherit;\n    transition: transform .4s cubic-bezier(.2,.7,.2,1), box-shadow .4s ease;\n    box-shadow: 0 24px 48px -32px rgba(45,55,72,.20);\n  }\n  .pair-card:hover{\n    transform: translateY(-6px);\n    box-shadow: 0 36px 72px -32px rgba(179,139,109,.45);\n  }\n\n  .pair-bg{\n    position:absolute; inset:0;\n    width:100%; height:100%;\n    z-index: 0;\n    transition: transform .8s cubic-bezier(.2,.7,.2,1);\n  }\n  .pair-card:hover .pair-bg{ transform: scale(1.04); }\n\n  .pair-overlay{\n    position:absolute; inset:0;\n    z-index: 1;\n    background:\n      linear-gradient(180deg, rgba(45,55,72,.25) 0%, rgba(45,55,72,.55) 60%, rgba(45,55,72,.82) 100%);\n    transition: background .4s ease;\n  }\n  .pair-card:hover .pair-overlay{\n    background:\n      linear-gradient(180deg, rgba(45,55,72,.30) 0%, rgba(45,55,72,.62) 60%, rgba(45,55,72,.88) 100%);\n  }\n\n  /* corner registration marks (Swiss tics, white) */\n  .pair-card .reg-w{\n    position:absolute;\n    width:14px; height:14px;\n    color: rgba(255,255,255,.45);\n    z-index: 2;\n  }\n  .pair-card .reg-w.tl{ top:18px; left:18px; border-top:1px solid currentColor; border-left:1px solid currentColor; }\n  .pair-card .reg-w.tr{ top:18px; right:18px; border-top:1px solid currentColor; border-right:1px solid currentColor; }\n\n  .pair-content{\n    position:absolute; inset:0;\n    z-index: 2;\n    padding: clamp(28px, 3.4vw, 44px);\n    display:flex; flex-direction:column;\n    justify-content: space-between;\n    color: #fff;\n  }\n  .pair-tag{\n    display:inline-flex; align-items:center; gap:8px;\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n    color: rgba(255,255,255,.78);\n    align-self: flex-start;\n  }\n  .pair-tag::before{\n    content:\"\"; width:6px; height:6px; border-radius:50%;\n    background: var(--accent-soft);\n  }\n\n  .pair-bottom{\n    display:flex; flex-direction:column;\n    gap: 18px;\n  }\n  .pair-title{\n    font-size: clamp(24px, 2.6vw, 36px);\n    font-weight: 700;\n    line-height: 1.08;\n    letter-spacing: -0.022em;\n    color: #fff;\n    margin: 0;\n    max-width: 16ch;\n  }\n  .pair-desc{\n    font-size: clamp(13.5px, 1vw, 14.5px);\n    line-height: 1.55;\n    color: rgba(255,255,255,.82);\n    margin: 0;\n    max-width: 50ch;\n    font-weight: 500;\n  }\n\n  .pair-cta{\n    margin-top: 6px;\n    display:inline-flex; align-items:center; gap: 10px;\n    font-size: 12px;\n    font-weight: 700;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n    color: #fff;\n    transition: gap .25s ease, color .25s ease;\n  }\n  .pair-cta svg{\n    transition: transform .3s ease;\n  }\n  .pair-card:hover .pair-cta{ gap: 14px; color: var(--accent-soft); }\n  .pair-card:hover .pair-cta svg{ transform: rotate(-12deg); }\n\n  @media (max-width: 1024px){\n    .pair-grid{ grid-template-columns: 1fr; }\n    .pair-h2{ grid-column: 1 / -1; }\n    .pair-sub{ grid-column: 1 / -1; padding-top: 14px; padding-bottom: 0; }\n  }\n  @media (max-width: 640px){\n    .pair-card{ aspect-ratio: 4 / 3; border-radius: 20px; }\n  }\n\n  /* ============ WHO WE SERVE ============ */\n  .serve{\n    position:relative;\n    background: var(--bg-alt);  /* #FAFAF8 */\n    padding: clamp(72px, 9vw, 128px) 0;\n    border-top: 1px solid var(--line-faint);\n    overflow:hidden;\n  }\n  .serve::before{\n    content:\"\";\n    position:absolute; inset:0;\n    background:\n      radial-gradient(700px 380px at 92% 12%, rgba(143,188,143,.08), transparent 70%),\n      radial-gradient(620px 320px at 6% 92%, rgba(179,139,109,.06), transparent 70%);\n    pointer-events:none;\n  }\n\n  .serve-head{\n    display:grid;\n    grid-template-columns: repeat(12, 1fr);\n    gap: var(--gutter);\n    align-items: end;\n    margin-bottom: clamp(48px, 6vw, 72px);\n    position:relative;\n  }\n  .serve-eyebrow{\n    grid-column: 1 / span 12;\n    display:inline-flex; align-items:center; gap:10px;\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .24em;\n    text-transform: uppercase;\n    color: var(--muted);\n    margin-bottom: 18px;\n  }\n  .serve-eyebrow::before{\n    content:\"\"; width:7px; height:7px; border-radius:50%;\n    background: var(--accent-soft);\n  }\n  .serve-h2{\n    grid-column: 1 / span 7;\n    font-size: clamp(34px, 4.2vw, 56px);\n    line-height: 1.04;\n    letter-spacing: -0.025em;\n    color: var(--heading);\n    font-weight: 700;\n    margin: 0;\n    max-width: 16ch;\n  }\n  .serve-sub{\n    grid-column: 9 / span 4;\n    font-size: 15.5px;\n    line-height: 1.65;\n    color: var(--body);\n    margin: 0;\n    padding-bottom: 8px;\n  }\n\n  .serve-grid{\n    display:grid;\n    grid-template-columns: repeat(3, 1fr);\n    gap: clamp(20px, 2.5vw, 28px);\n  }\n\n  .serve-card{\n    position:relative;\n    aspect-ratio: 4 / 5;\n    border-radius: 24px;\n    overflow:hidden;\n    isolation: isolate;\n    text-decoration: none;\n    color: inherit;\n    background: #fff;\n    border: 1px solid var(--line-soft);\n    transition: transform .5s cubic-bezier(.2,.7,.2,1), box-shadow .5s ease, border-color .4s ease;\n  }\n  .serve-card:hover{\n    transform: translateY(-8px);\n    border-color: var(--line);\n    box-shadow: 0 40px 80px -36px rgba(179,139,109,.50);\n  }\n\n  .serve-img{\n    position:absolute; inset: 0;\n    width:100%; height:100%;\n    z-index: 0;\n    transition: transform .8s cubic-bezier(.2,.7,.2,1);\n  }\n  .serve-card:hover .serve-img{ transform: scale(1.05); }\n  .serve-img svg{ width:100%; height:100%; display:block; }\n\n  .serve-overlay{\n    position:absolute; inset:0;\n    z-index: 1;\n    background:\n      linear-gradient(180deg, rgba(45,55,72,0) 0%, rgba(45,55,72,.30) 45%, rgba(45,55,72,.85) 100%);\n    transition: background .4s ease;\n  }\n  .serve-card:hover .serve-overlay{\n    background:\n      linear-gradient(180deg, rgba(45,55,72,.05) 0%, rgba(45,55,72,.40) 45%, rgba(45,55,72,.92) 100%);\n  }\n\n  .serve-num{\n    position: absolute;\n    top: 20px; left: 20px;\n    z-index: 3;\n    display:inline-flex; align-items:center; gap:8px;\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n    color: rgba(255,255,255,.92);\n    padding: 7px 12px;\n    background: rgba(255,255,255,.14);\n    backdrop-filter: blur(10px);\n    -webkit-backdrop-filter: blur(10px);\n    border: 1px solid rgba(255,255,255,.20);\n    border-radius: 999px;\n  }\n  .serve-num::before{\n    content:\"\"; width:5px; height:5px; border-radius:50%;\n    background: var(--accent-soft);\n  }\n\n  .serve-arrow{\n    position: absolute;\n    top: 20px; right: 20px;\n    z-index: 3;\n    width: 40px; height: 40px;\n    border-radius: 50%;\n    border: 1px solid rgba(255,255,255,.30);\n    background: rgba(255,255,255,.14);\n    backdrop-filter: blur(10px);\n    -webkit-backdrop-filter: blur(10px);\n    color: #fff;\n    display:grid; place-items:center;\n    transition: background .35s, border-color .35s, transform .45s, color .35s;\n  }\n  .serve-card:hover .serve-arrow{\n    background: var(--line);\n    border-color: var(--line);\n    color: #fff;\n    transform: rotate(-15deg);\n  }\n\n  .serve-content{\n    position:absolute; left:0; right:0; bottom:0;\n    z-index: 2;\n    padding: clamp(24px, 2.6vw, 32px);\n    color: #fff;\n    display:flex; flex-direction:column;\n    gap: 14px;\n  }\n\n  .serve-tag{\n    display:inline-flex; align-items:center; gap: 8px;\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n    color: rgba(255,255,255,.78);\n    align-self: flex-start;\n  }\n  .serve-tag::before{\n    content:\"\"; width:5px; height:5px; border-radius:50%;\n    background: var(--line);\n  }\n\n  .serve-title{\n    font-size: clamp(22px, 2vw, 28px);\n    font-weight: 700;\n    line-height: 1.12;\n    letter-spacing: -0.022em;\n    color: #fff;\n    margin: 0;\n    max-width: 16ch;\n  }\n\n  .serve-desc{\n    font-size: 13.5px;\n    line-height: 1.55;\n    color: rgba(255,255,255,.88);\n    margin: 0;\n    max-width: 38ch;\n    max-height: 0;\n    opacity: 0;\n    overflow: hidden;\n    transition: max-height .5s cubic-bezier(.2,.7,.2,1), opacity .4s ease;\n  }\n  .serve-card:hover .serve-desc{\n    max-height: 200px;\n    opacity: 1;\n  }\n\n  .serve-points{\n    list-style: none;\n    margin: 0; padding: 0;\n    display:flex; flex-wrap:wrap;\n    gap: 6px;\n  }\n  .serve-points li{\n    display:inline-flex; align-items:center; gap:6px;\n    padding: 5px 10px 5px 8px;\n    background: rgba(255,255,255,.12);\n    border: 1px solid rgba(255,255,255,.18);\n    border-radius: 999px;\n    font-size: 11px;\n    font-weight: 600;\n    color: rgba(255,255,255,.92);\n    backdrop-filter: blur(8px);\n    -webkit-backdrop-filter: blur(8px);\n  }\n  .serve-points li::before{\n    content:\"\";\n    width: 4px; height: 4px;\n    border-radius: 50%;\n    background: var(--accent-soft);\n  }\n\n  @media (max-width: 1024px){\n    .serve-grid{ grid-template-columns: 1fr; }\n    .serve-card{ aspect-ratio: 4 / 3; }\n    .serve-h2{ grid-column: 1 / -1; }\n    .serve-sub{ grid-column: 1 / -1; padding-top: 14px; padding-bottom: 0; }\n    .serve-desc{ max-height: 200px; opacity: 1; }\n  }\n  @media (max-width: 640px){\n    .serve-card{ aspect-ratio: 5 / 4; border-radius: 20px; }\n  }\n\n  /* ============ CTA BANNER ============ */\n  .cta-banner{\n    position:relative;\n    background: var(--bg);  /* #F8F9FA */\n    padding: clamp(56px, 7vw, 96px) 0 clamp(72px, 9vw, 120px);\n  }\n\n  .cta-card{\n    position:relative;\n    border-radius: 32px;\n    overflow:hidden;\n    isolation: isolate;\n    padding: clamp(72px, 10vw, 144px) clamp(28px, 4vw, 64px);\n    background:\n      linear-gradient(180deg, #2D3748 0%, #1F2837 100%);\n    box-shadow: 0 40px 100px -50px rgba(45,55,72,.40);\n  }\n  .cta-card::before{\n    content:\"\";\n    position:absolute; inset:0;\n    background:\n      radial-gradient(680px 360px at 88% 12%, rgba(143,188,143,.18), transparent 70%),\n      radial-gradient(620px 320px at 8% 92%, rgba(179,139,109,.14), transparent 70%);\n    pointer-events:none;\n    z-index: 0;\n  }\n  .cta-card::after{\n    content:\"\";\n    position:absolute; inset:0;\n    background-image:\n      linear-gradient(to right, rgba(255,255,255,.04) 1px, transparent 1px);\n    background-size: calc(100% / 8) 100%;\n    pointer-events:none;\n    z-index: 0;\n    opacity: .55;\n  }\n  .cta-card > *{ position:relative; z-index: 1; }\n\n  .cta-card .reg-w{\n    position:absolute;\n    width:14px; height:14px;\n    color: rgba(255,255,255,.30);\n    z-index: 2;\n  }\n  .cta-card .reg-w.tl{ top:24px; left:24px; border-top:1px solid currentColor; border-left:1px solid currentColor; }\n  .cta-card .reg-w.tr{ top:24px; right:24px; border-top:1px solid currentColor; border-right:1px solid currentColor; }\n  .cta-card .reg-w.bl{ bottom:24px; left:24px; border-bottom:1px solid currentColor; border-left:1px solid currentColor; }\n  .cta-card .reg-w.br{ bottom:24px; right:24px; border-bottom:1px solid currentColor; border-right:1px solid currentColor; }\n\n  .cta-inner{\n    text-align: center;\n    max-width: 760px;\n    margin: 0 auto;\n    display:flex; flex-direction:column;\n    align-items:center;\n    gap: clamp(20px, 2.4vw, 28px);\n  }\n\n  .cta-eyebrow{\n    display:inline-flex; align-items:center; gap:10px;\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .24em;\n    text-transform: uppercase;\n    color: rgba(255,255,255,.70);\n  }\n  .cta-eyebrow::before{\n    content:\"\"; width:7px; height:7px; border-radius:50%;\n    background: var(--accent-soft);\n    box-shadow: 0 0 0 5px rgba(143,188,143,.22);\n  }\n\n  .cta-h2{\n    font-size: clamp(40px, 6vw, 80px);\n    line-height: 1.02;\n    letter-spacing: -0.030em;\n    color: #fff;\n    font-weight: 700;\n    margin: 0;\n    text-wrap: balance;\n  }\n  .cta-h2 em{\n    font-style: normal;\n    position: relative;\n    display: inline-block;\n    color: #fff;\n  }\n  .cta-h2 em::before{\n    content:\"\";\n    position:absolute;\n    left: -2px; right: -2px;\n    bottom: 0.06em;\n    height: 14px;\n    background: linear-gradient(90deg, rgba(179,139,109,.55), rgba(143,188,143,.50));\n    border-radius: 3px;\n    z-index: -1;\n    transform: skewX(-6deg);\n  }\n\n  .cta-text{\n    font-size: clamp(15px, 1.2vw, 17px);\n    line-height: 1.65;\n    color: rgba(255,255,255,.78);\n    margin: 0;\n    max-width: 56ch;\n    font-weight: 500;\n  }\n\n  .cta-row{\n    display:flex; align-items:center;\n    gap: 28px;\n    flex-wrap: wrap;\n    justify-content: center;\n    margin-top: 8px;\n  }\n\n  .cta-primary{\n    display:inline-flex; align-items:center; gap: 10px;\n    padding: 16px 28px 16px 24px;\n    background: var(--cta);\n    color: #fff;\n    font-family: inherit;\n    font-size: 15px;\n    font-weight: 600;\n    letter-spacing: -0.005em;\n    border-radius: 999px;\n    text-decoration: none;\n    border: 0;\n    cursor: pointer;\n    box-shadow:\n      0 1px 0 rgba(255,255,255,.20) inset,\n      0 12px 32px -10px rgba(87,109,181,.65);\n    transition: transform .2s, background .2s, box-shadow .25s;\n  }\n  .cta-primary:hover{\n    background: var(--cta-hover);\n    transform: translateY(-2px);\n    box-shadow:\n      0 1px 0 rgba(255,255,255,.20) inset,\n      0 18px 42px -10px rgba(87,109,181,.75);\n  }\n  .cta-primary svg{ transition: transform .25s; }\n  .cta-primary:hover svg{ transform: translateX(3px); }\n\n  .cta-secondary{\n    display:inline-flex; align-items:center; gap: 10px;\n    padding: 14px 18px;\n    color: #fff;\n    font-size: 14px;\n    font-weight: 600;\n    letter-spacing: -0.005em;\n    border-bottom: 1px solid transparent;\n    transition: border-color .2s, gap .25s;\n  }\n  .cta-secondary:hover{\n    border-bottom-color: rgba(255,255,255,.6);\n    gap: 14px;\n  }\n  .cta-secondary svg{ transition: transform .25s; }\n  .cta-secondary:hover svg{ transform: rotate(-12deg); }\n  .cta-secondary .ico{\n    width: 28px; height: 28px;\n    border-radius: 50%;\n    border: 1px solid rgba(255,255,255,.30);\n    display:grid; place-items:center;\n    flex: 0 0 28px;\n    transition: border-color .25s, background .25s;\n  }\n  .cta-secondary:hover .ico{\n    border-color: var(--line);\n    background: var(--line);\n  }\n\n  .cta-card .plus-mark{\n    position:absolute;\n    color: rgba(179,139,109,.40);\n    z-index: 1;\n  }\n  .cta-card .plus-mark svg{ display:block; }\n  .cta-card .plus-mark.pm1{ top: 18%; left: 12%; }\n  .cta-card .plus-mark.pm2{ top: 22%; right: 14%; }\n  .cta-card .plus-mark.pm3{ bottom: 24%; left: 16%; }\n  .cta-card .plus-mark.pm4{ bottom: 20%; right: 10%; }\n\n  @media (max-width: 640px){\n    .cta-card{ border-radius: 24px; }\n    .cta-card .reg-w{ width: 12px; height: 12px; }\n    .cta-card .plus-mark{ display: none; }\n    .cta-row{ flex-direction: column; gap: 14px; }\n    .cta-primary{ width: 100%; justify-content: center; }\n  }\n\n  /* ============ BOOKING MODAL ============ */\n  .modal-backdrop{\n    position: fixed; inset: 0;\n    background: rgba(45, 55, 72, .55);\n    backdrop-filter: blur(8px) saturate(140%);\n    -webkit-backdrop-filter: blur(8px) saturate(140%);\n    z-index: 100;\n    display: none;\n    opacity: 0;\n    transition: opacity .25s ease;\n  }\n  .modal-backdrop.is-open{\n    display: grid;\n    place-items: center;\n    padding: clamp(16px, 3vw, 32px);\n    opacity: 1;\n  }\n\n  .modal{\n    position: relative;\n    width: 100%;\n    max-width: 920px;\n    max-height: calc(100vh - 64px);\n    background: #fff;\n    border-radius: 24px;\n    border: 1px solid var(--line-soft);\n    box-shadow: 0 60px 120px -40px rgba(45, 55, 72, .45);\n    overflow: hidden;\n    display: grid;\n    grid-template-columns: 1fr 1.4fr;\n    transform: translateY(20px);\n    opacity: 0;\n    transition: transform .35s cubic-bezier(.2,.7,.2,1), opacity .25s ease;\n  }\n  .modal-backdrop.is-open .modal{\n    transform: translateY(0);\n    opacity: 1;\n  }\n\n  .modal-close{\n    position: absolute;\n    top: 18px; right: 18px;\n    width: 36px; height: 36px;\n    border-radius: 50%;\n    background: rgba(255,255,255,.92);\n    backdrop-filter: blur(8px);\n    border: 1px solid var(--line-soft);\n    color: var(--heading);\n    display: grid; place-items: center;\n    cursor: pointer;\n    z-index: 10;\n    transition: background .25s, border-color .25s, transform .25s;\n  }\n  .modal-close:hover{\n    background: var(--line);\n    border-color: var(--line);\n    color: #fff;\n    transform: rotate(90deg);\n  }\n\n  /* LEFT panel — info */\n  .modal-info{\n    padding: clamp(28px, 3vw, 40px);\n    background: var(--bg-alt);\n    border-right: 1px solid var(--line-faint);\n    display: flex; flex-direction: column;\n    gap: 20px;\n    overflow-y: auto;\n  }\n  .modal-eyebrow{\n    display:inline-flex; align-items:center; gap:10px;\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n    color: var(--muted);\n  }\n  .modal-eyebrow::before{\n    content:\"\"; width:7px; height:7px; border-radius:50%;\n    background: var(--accent-soft);\n    box-shadow: 0 0 0 4px rgba(143,188,143,.20);\n  }\n  .modal-title{\n    font-size: clamp(22px, 2vw, 28px);\n    font-weight: 700;\n    line-height: 1.15;\n    letter-spacing: -0.022em;\n    color: var(--heading);\n    margin: 0;\n  }\n  .modal-text{\n    font-size: 14px;\n    line-height: 1.6;\n    color: var(--body);\n    margin: 0;\n  }\n  .modal-list{\n    list-style: none;\n    margin: 0; padding: 0;\n    display: flex; flex-direction: column;\n    gap: 10px;\n  }\n  .modal-list li{\n    display: flex; align-items: flex-start; gap: 10px;\n    font-size: 13px;\n    color: var(--body);\n    line-height: 1.5;\n    font-weight: 500;\n  }\n  .modal-list .check{\n    width: 20px; height: 20px;\n    border-radius: 50%;\n    background: rgba(143,188,143,.20);\n    color: var(--accent-soft);\n    display: grid; place-items: center;\n    flex: 0 0 20px;\n    margin-top: 1px;\n  }\n  .modal-foot{\n    margin-top: auto;\n    padding-top: 16px;\n    border-top: 1px solid var(--line-faint);\n    font-size: 11.5px;\n    color: var(--muted);\n    line-height: 1.5;\n    display: flex; align-items: center; gap: 8px;\n  }\n  .modal-foot::before{\n    content:\"\"; width:6px; height:6px; border-radius:50%;\n    background: var(--line);\n    flex: 0 0 6px;\n  }\n\n  /* RIGHT panel — calendar */\n  .modal-cal{\n    padding: clamp(28px, 3vw, 36px);\n    display: flex; flex-direction: column;\n    gap: 18px;\n    overflow-y: auto;\n    background: #fff;\n  }\n  .cal-head{\n    display: flex; align-items: center; justify-content: space-between;\n  }\n  .cal-month{\n    font-size: 16px;\n    font-weight: 700;\n    color: var(--heading);\n    letter-spacing: -0.012em;\n  }\n  .cal-nav{\n    display: flex; gap: 8px;\n  }\n  .cal-nav button{\n    width: 32px; height: 32px;\n    border-radius: 50%;\n    border: 1px solid var(--line-soft);\n    color: var(--heading);\n    background: #fff;\n    display: grid; place-items: center;\n    cursor: pointer;\n    transition: border-color .2s, background .2s, color .2s;\n  }\n  .cal-nav button:hover{\n    border-color: var(--line);\n    background: var(--line);\n    color: #fff;\n  }\n  .cal-nav button:disabled{\n    opacity: .35;\n    cursor: not-allowed;\n  }\n  .cal-nav button:disabled:hover{\n    border-color: var(--line-soft);\n    background: #fff;\n    color: var(--heading);\n  }\n\n  .cal-weekdays{\n    display: grid;\n    grid-template-columns: repeat(7, 1fr);\n    gap: 4px;\n  }\n  .cal-weekdays span{\n    font-size: 10px;\n    font-weight: 700;\n    letter-spacing: .14em;\n    text-transform: uppercase;\n    color: var(--muted);\n    text-align: center;\n    padding: 8px 0 4px;\n  }\n\n  .cal-grid{\n    display: grid;\n    grid-template-columns: repeat(7, 1fr);\n    gap: 4px;\n  }\n  .cal-day{\n    aspect-ratio: 1;\n    border-radius: 50%;\n    border: 1px solid transparent;\n    background: transparent;\n    color: var(--heading);\n    font-family: inherit;\n    font-size: 13.5px;\n    font-weight: 500;\n    cursor: pointer;\n    transition: background .2s, color .2s, border-color .2s;\n  }\n  .cal-day.is-empty{\n    cursor: default;\n    color: transparent;\n    pointer-events: none;\n  }\n  .cal-day.is-past,\n  .cal-day.is-disabled{\n    color: var(--muted);\n    opacity: .35;\n    cursor: not-allowed;\n  }\n  .cal-day:not(.is-empty):not(.is-past):not(.is-disabled):hover{\n    background: rgba(179,139,109,.12);\n    border-color: var(--line-soft);\n  }\n  .cal-day.is-today{\n    border-color: var(--line);\n    color: var(--line);\n    font-weight: 700;\n  }\n  .cal-day.is-selected{\n    background: var(--cta);\n    color: #fff;\n    border-color: var(--cta);\n    font-weight: 700;\n  }\n\n  .cal-times{\n    display: grid;\n    grid-template-columns: repeat(3, 1fr);\n    gap: 8px;\n    padding-top: 16px;\n    border-top: 1px solid var(--line-faint);\n  }\n  .cal-times-empty{\n    grid-column: 1 / -1;\n    text-align: center;\n    font-size: 12.5px;\n    color: var(--muted);\n    padding: 14px 0;\n    font-weight: 500;\n  }\n  .cal-time{\n    padding: 10px 8px;\n    border-radius: 10px;\n    border: 1px solid var(--line-soft);\n    background: #fff;\n    color: var(--heading);\n    font-family: inherit;\n    font-size: 13px;\n    font-weight: 600;\n    cursor: pointer;\n    transition: border-color .2s, background .2s, color .2s, transform .15s;\n  }\n  .cal-time:hover{\n    border-color: var(--line);\n    background: rgba(179,139,109,.06);\n    transform: translateY(-1px);\n  }\n  .cal-time.is-selected{\n    background: var(--cta);\n    border-color: var(--cta);\n    color: #fff;\n  }\n\n  .cal-confirm{\n    margin-top: 8px;\n    width: 100%;\n    padding: 14px 8px 14px 22px;\n    background: var(--cta);\n    color: #fff;\n    border-radius: 999px;\n    font-family: inherit;\n    font-size: 14.5px;\n    font-weight: 600;\n    border: 0;\n    cursor: pointer;\n    display: inline-flex; align-items: center; justify-content: space-between;\n    gap: 12px;\n    transition: background .2s, transform .2s;\n  }\n  .cal-confirm:hover{\n    background: var(--cta-hover);\n    transform: translateY(-2px);\n  }\n  .cal-confirm:disabled{\n    opacity: .5;\n    cursor: not-allowed;\n  }\n  .cal-confirm:disabled:hover{\n    transform: none;\n  }\n  .cal-confirm .ico{\n    width: 28px; height: 28px;\n    border-radius: 50%;\n    background: rgba(255,255,255,.20);\n    display: grid; place-items: center;\n    flex: 0 0 28px;\n  }\n\n  @media (max-width: 720px){\n    .modal{ grid-template-columns: 1fr; max-height: 92vh; }\n    .modal-info{ display: none; }\n  }\n\n  /* ============ TRUST & INFRASTRUCTURE ============ */\n  .trust{\n    position:relative;\n    background: var(--bg-alt);  /* #FAFAF8 */\n    padding: clamp(72px, 9vw, 128px) 0;\n    border-top: 1px solid var(--line-faint);\n    overflow:hidden;\n  }\n  .trust::before{\n    content:\"\";\n    position:absolute; inset:0;\n    background:\n      radial-gradient(800px 420px at 88% 8%, rgba(143,188,143,.08), transparent 70%),\n      radial-gradient(620px 320px at 6% 94%, rgba(179,139,109,.06), transparent 70%);\n    pointer-events:none;\n  }\n\n  .trust-grid{\n    display:grid;\n    grid-template-columns: 1fr 1.4fr;\n    gap: clamp(32px, 4vw, 64px);\n    align-items: start;\n    position:relative;\n  }\n\n  /* LEFT: header */\n  .trust-head{\n    position: sticky;\n    top: 110px;\n    display:flex; flex-direction:column;\n    gap: clamp(20px, 2.4vw, 28px);\n  }\n  .trust-eyebrow{\n    display:inline-flex; align-items:center; gap:10px;\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .24em;\n    text-transform: uppercase;\n    color: var(--muted);\n    max-width: max-content;\n  }\n  .trust-eyebrow::before{\n    content:\"\"; width:7px; height:7px; border-radius:50%;\n    background: var(--accent-soft);\n    box-shadow: 0 0 0 4px rgba(143,188,143,.20);\n  }\n  .trust-h2{\n    font-size: clamp(34px, 4.2vw, 56px);\n    line-height: 1.04;\n    letter-spacing: -0.025em;\n    color: var(--heading);\n    font-weight: 700;\n    margin: 0;\n    max-width: 14ch;\n    text-wrap: balance;\n  }\n  .trust-sub{\n    font-size: 15.5px;\n    line-height: 1.65;\n    color: var(--body);\n    margin: 0;\n    max-width: 42ch;\n    font-weight: 500;\n  }\n\n  .trust-cta{\n    display:inline-flex; align-items:center; gap: 10px;\n    margin-top: 8px;\n    color: var(--heading);\n    font-size: 14px;\n    font-weight: 600;\n    letter-spacing: -0.005em;\n    text-decoration: none;\n    transition: gap .25s ease, color .2s;\n    align-self: flex-start;\n  }\n  .trust-cta:hover{ color: var(--cta); gap: 14px; }\n  .trust-cta .ico{\n    width: 32px; height: 32px;\n    border-radius: 50%;\n    border: 1px solid var(--line-soft);\n    color: var(--line);\n    display: grid; place-items: center;\n    transition: border-color .25s, background .25s, color .25s, transform .3s;\n  }\n  .trust-cta:hover .ico{\n    border-color: var(--line);\n    background: var(--line);\n    color: #fff;\n    transform: rotate(-12deg);\n  }\n\n  /* RIGHT: 2 cards */\n  .trust-cards{\n    display:grid;\n    grid-template-columns: 1fr 1fr;\n    gap: clamp(16px, 2vw, 22px);\n  }\n\n  .trust-card{\n    position:relative;\n    display:flex; flex-direction:column;\n    gap: 22px;\n    padding: clamp(28px, 3vw, 40px);\n    border-radius: 22px;\n    background: rgba(255,255,255,.65);\n    backdrop-filter: blur(14px) saturate(140%);\n    -webkit-backdrop-filter: blur(14px) saturate(140%);\n    border: 1px solid var(--line-soft);\n    text-decoration: none;\n    color: inherit;\n    overflow: hidden;\n    isolation: isolate;\n    transition: transform .45s cubic-bezier(.2,.7,.2,1), border-color .35s ease, box-shadow .45s ease, background .35s ease;\n    min-height: 360px;\n  }\n  .trust-card::before{\n    content:\"\";\n    position:absolute;\n    top: 0; left: 0; right: 0;\n    height: 3px;\n    background: linear-gradient(90deg, var(--line) 0%, var(--accent-soft) 100%);\n    transform: scaleX(0);\n    transform-origin: left;\n    transition: transform .55s cubic-bezier(.2,.7,.2,1);\n    z-index: 1;\n  }\n  .trust-card:hover{\n    transform: translateY(-6px);\n    border-color: var(--line);\n    background: #fff;\n    box-shadow: 0 36px 72px -36px rgba(179,139,109,.40);\n  }\n  .trust-card:hover::before{ transform: scaleX(1); }\n\n  /* Featured card variant — solid CTA-blue like reference */\n  .trust-card.is-featured{\n    background: linear-gradient(180deg, var(--cta) 0%, var(--cta-hover) 100%);\n    border-color: rgba(255,255,255,.18);\n    color: #fff;\n  }\n  .trust-card.is-featured::after{\n    content:\"\";\n    position:absolute;\n    inset: 0;\n    background:\n      radial-gradient(420px 220px at 92% 8%, rgba(143,188,143,.18), transparent 65%),\n      radial-gradient(320px 200px at 8% 94%, rgba(179,139,109,.14), transparent 70%);\n    pointer-events: none;\n    z-index: 0;\n  }\n  .trust-card.is-featured::before{\n    background: linear-gradient(90deg, rgba(255,255,255,.5), rgba(143,188,143,.7));\n  }\n  .trust-card.is-featured > *{ position: relative; z-index: 1; }\n  .trust-card.is-featured:hover{\n    background: linear-gradient(180deg, var(--cta-hover) 0%, #3A4DA0 100%);\n    border-color: rgba(255,255,255,.30);\n    box-shadow: 0 36px 72px -36px rgba(87,109,181,.55);\n  }\n\n  /* Header row inside card */\n  .trust-card-head{\n    display:flex; align-items:flex-start; justify-content: space-between;\n    gap: 16px;\n  }\n  .trust-icon{\n    width: 52px; height: 52px;\n    border-radius: 14px;\n    background: rgba(143,188,143,.16);\n    color: var(--accent-soft);\n    display: grid; place-items: center;\n    flex: 0 0 52px;\n    transition: background .35s, color .35s, transform .45s;\n  }\n  .trust-card.is-featured .trust-icon{\n    background: rgba(255,255,255,.18);\n    color: #fff;\n  }\n  .trust-card:hover .trust-icon{\n    transform: rotate(-8deg) scale(1.05);\n  }\n\n  .trust-arrow{\n    width: 40px; height: 40px;\n    border-radius: 50%;\n    background: rgba(255,255,255,.92);\n    border: 1px solid var(--line-soft);\n    color: var(--line);\n    display: grid; place-items: center;\n    flex: 0 0 40px;\n    transition: background .3s, color .3s, transform .35s, border-color .3s;\n  }\n  .trust-card:hover .trust-arrow{\n    background: var(--line);\n    border-color: var(--line);\n    color: #fff;\n    transform: rotate(-12deg);\n  }\n  .trust-card.is-featured .trust-arrow{\n    background: rgba(255,255,255,.18);\n    border-color: rgba(255,255,255,.28);\n    color: #fff;\n  }\n  .trust-card.is-featured:hover .trust-arrow{\n    background: #fff;\n    border-color: #fff;\n    color: var(--cta);\n  }\n\n  .trust-tag{\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n    color: var(--muted);\n    display:inline-flex; align-items:center; gap: 8px;\n  }\n  .trust-tag::before{\n    content:\"\"; width:6px; height:6px; border-radius:50%;\n    background: var(--line);\n  }\n  .trust-card.is-featured .trust-tag{ color: rgba(255,255,255,.75); }\n  .trust-card.is-featured .trust-tag::before{ background: var(--accent-soft); }\n\n  .trust-title{\n    font-size: clamp(22px, 2vw, 28px);\n    font-weight: 700;\n    line-height: 1.18;\n    letter-spacing: -0.022em;\n    color: var(--heading);\n    margin: 0;\n    max-width: 14ch;\n  }\n  .trust-card.is-featured .trust-title{ color: #fff; }\n\n  .trust-text{\n    font-size: 14px;\n    line-height: 1.6;\n    color: var(--body);\n    margin: 0;\n    max-width: 36ch;\n  }\n  .trust-card.is-featured .trust-text{ color: rgba(255,255,255,.82); }\n\n  /* Bullet feature list */\n  .trust-list{\n    list-style: none;\n    margin: 0; padding: 16px 0 0;\n    border-top: 1px solid var(--line-faint);\n    display: flex; flex-direction: column; gap: 10px;\n    margin-top: auto;\n  }\n  .trust-card.is-featured .trust-list{ border-top-color: rgba(255,255,255,.20); }\n\n  .trust-list li{\n    display: flex; align-items: flex-start; gap: 10px;\n    font-size: 13px;\n    color: var(--body);\n    line-height: 1.5;\n    font-weight: 500;\n  }\n  .trust-card.is-featured .trust-list li{ color: rgba(255,255,255,.85); }\n\n  .trust-list li::before{\n    content:\"\";\n    width: 6px; height: 6px;\n    border-radius: 50%;\n    background: var(--cta);\n    margin-top: 7px;\n    flex: 0 0 6px;\n  }\n  .trust-card.is-featured .trust-list li::before{ background: var(--accent-soft); }\n\n  @media (max-width: 1024px){\n    .trust-grid{ grid-template-columns: 1fr; gap: 40px; }\n    .trust-head{ position: static; }\n    .trust-cards{ grid-template-columns: 1fr 1fr; }\n  }\n  @media (max-width: 720px){\n    .trust-cards{ grid-template-columns: 1fr; }\n    .trust-card{ min-height: auto; }\n  }\n\n  /* ============ FOOTER ============ */\n  .footer{\n    position:relative;\n    background:\n      linear-gradient(180deg, rgba(248,249,250,.4), rgba(248,249,250,.95)),\n      radial-gradient(800px 420px at 88% 10%, rgba(143,188,143,.10), transparent 70%),\n      radial-gradient(720px 380px at 8% 92%, rgba(179,139,109,.08), transparent 70%),\n      var(--bg);\n    border-top: 1px solid var(--line-soft);\n    padding: clamp(72px, 9vw, 112px) 0 28px;\n    backdrop-filter: blur(14px) saturate(140%);\n    -webkit-backdrop-filter: blur(14px) saturate(140%);\n  }\n\n  .ft-grid{\n    display:grid;\n    grid-template-columns: 1.4fr 1fr 1fr 1.4fr;\n    gap: clamp(32px, 4vw, 56px) clamp(24px, 3vw, 40px);\n    position: relative;\n  }\n\n  /* Brand block */\n  .ft-brand{\n    display:flex; flex-direction:column;\n    gap: 22px;\n    max-width: 360px;\n  }\n  .ft-logo{ display:inline-block; }\n  .ft-logo img{\n    height: 38px;\n    width: auto;\n    display:block;\n  }\n  .ft-desc{\n    font-size: 14px;\n    line-height: 1.65;\n    color: var(--body);\n    margin: 0;\n    max-width: 38ch;\n  }\n  .ft-social{\n    display:flex; gap: 10px;\n    margin-top: 4px;\n  }\n  .ft-social a{\n    width: 40px; height: 40px;\n    border-radius: 50%;\n    display:grid; place-items:center;\n    border: 1px solid var(--line-soft);\n    background: rgba(255,255,255,.55);\n    backdrop-filter: blur(10px);\n    -webkit-backdrop-filter: blur(10px);\n    color: var(--heading);\n    transition: background .25s, border-color .25s, color .25s, transform .25s;\n  }\n  .ft-social a:hover{\n    background: var(--line);\n    border-color: var(--line);\n    color: #fff;\n    transform: translateY(-2px);\n  }\n\n  /* Link columns */\n  .ft-col{\n    display:flex; flex-direction:column;\n    gap: 18px;\n  }\n  .ft-h{\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: .22em;\n    text-transform: uppercase;\n    color: var(--heading);\n    margin: 0;\n    display:inline-flex; align-items:center; gap:8px;\n  }\n  .ft-h::before{\n    content:\"\"; width:5px; height:5px; border-radius:50%;\n    background: var(--line);\n  }\n  .ft-list{\n    list-style:none;\n    margin:0; padding:0;\n    display:flex; flex-direction:column;\n    gap: 11px;\n  }\n  .ft-list a,\n  .ft-list .ft-text{\n    font-size: 13.5px;\n    line-height: 1.5;\n    color: var(--body);\n    text-decoration: none;\n    position: relative;\n    transition: color .2s;\n    display: inline-block;\n  }\n  .ft-list a::after{\n    content:\"\";\n    position:absolute;\n    left: 0; bottom: -2px;\n    width: 0; height: 1px;\n    background: var(--line);\n    transition: width .25s ease;\n  }\n  .ft-list a:hover{ color: var(--heading); }\n  .ft-list a:hover::after{ width: 100%; }\n\n  .ft-list .ft-text{ color: var(--body); }\n  .ft-list a.ft-text-link{ color: var(--body); }\n\n  /* Newsletter */\n  .ft-news{\n    margin-top: 8px;\n    padding-top: 22px;\n    border-top: 1px solid var(--line-faint);\n  }\n  .ft-news-h{\n    font-size: 14px;\n    font-weight: 700;\n    color: var(--heading);\n    margin: 0 0 6px;\n    letter-spacing: -0.01em;\n  }\n  .ft-news-p{\n    font-size: 12.5px;\n    color: var(--muted);\n    margin: 0 0 14px;\n    line-height: 1.5;\n  }\n  .ft-form{\n    display:flex; align-items:center;\n    background: rgba(255,255,255,.6);\n    backdrop-filter: blur(10px);\n    -webkit-backdrop-filter: blur(10px);\n    border: 1px solid var(--line-soft);\n    border-radius: 999px;\n    padding: 4px 4px 4px 6px;\n    gap: 4px;\n    transition: border-color .25s, background .25s;\n  }\n  .ft-form:focus-within{\n    border-color: var(--line);\n    background: #fff;\n  }\n  .ft-form input{\n    flex: 1;\n    border: 0;\n    background: transparent;\n    padding: 10px 14px;\n    font-size: 13px;\n    font-family: inherit;\n    color: var(--heading);\n    outline: 0;\n    min-width: 0;\n  }\n  .ft-form input::placeholder{ color: var(--muted); }\n  .ft-form button{\n    padding: 10px 18px;\n    border-radius: 999px;\n    background: var(--cta);\n    color: #fff;\n    font-size: 12.5px;\n    font-weight: 600;\n    letter-spacing: .02em;\n    cursor: pointer;\n    border: 0;\n    display:inline-flex; align-items:center; gap: 6px;\n    flex: 0 0 auto;\n    transition: background .2s, transform .15s;\n  }\n  .ft-form button:hover{ background: var(--cta-hover); transform: translateY(-1px); }\n\n  /* Bottom row */\n  .ft-bottom{\n    margin-top: clamp(56px, 7vw, 80px);\n    padding-top: 22px;\n    border-top: 1px solid var(--line-faint);\n    display:flex; justify-content:space-between; align-items:center;\n    gap: 16px;\n    flex-wrap: wrap;\n    font-size: 12.5px;\n    color: var(--muted);\n  }\n  .ft-bottom-links{\n    display:flex; gap: 22px;\n    flex-wrap: wrap;\n  }\n  .ft-bottom-links a{\n    color: var(--muted);\n    transition: color .2s;\n  }\n  .ft-bottom-links a:hover{ color: var(--heading); }\n\n  @media (max-width: 1024px){\n    .ft-grid{ grid-template-columns: 1fr 1fr; }\n    .ft-brand{ grid-column: 1 / -1; max-width: 480px; }\n  }\n  @media (max-width: 640px){\n    .ft-grid{ grid-template-columns: 1fr; gap: 36px; }\n    .ft-brand{ grid-column: auto; }\n    .ft-bottom{ flex-direction: column; align-items: flex-start; }\n  }";
